/** Returns a map of { "HH:MI" → bookedCount } for a given date, excluding cancelled bookings. */
async function getSlotCountMap(db: DbInterface, dateStr: string): Promise<Record<string, number>> {
  const rows = await db.query(
    "SELECT TO_CHAR(booking_time, 'HH24:MI') as t, COUNT(*) as count FROM bookings WHERE TO_CHAR(booking_date, 'YYYY-MM-DD') = ? AND status != 'CANCELLED' GROUP BY t",
    [dateStr]
  );
  const map: Record<string, number> = {};
  for (const r of rows) map[r.t] = Number(r.count);
  return map;
}

function extractDriveId(url: string) {
  if (!url) return null;
  const match = url.match(/[-\w]{25,}/);
  return match ? match[0] : null;
}

// ──────────────────────────────────────────────────────────────────────────
// T1-S7 — Multer MIME whitelists (BCG audit, Tier 1 follow-up)
// ──────────────────────────────────────────────────────────────────────────
// Pre-S7, multer accepted ANY MIME type. A malicious actor could upload
// .exe / .sh / .html with arbitrary content, and the server happily wrote
// it to /uploads/ where it was statically served. Routes most at risk:
//   • /logo, /watermark, /upi-qr — owner can upload anything
//   • /menu/:id/upload — image-only intent, no validation
//   • /hotel/.../id-docs — guest ID proof (KYC), should be image/PDF only
//   • /grn/:id/upload-bill — supplier bill, image/PDF only
//   • /inventory/receipt-ocr — same
// All routes now reject anything outside the relevant whitelist with 415.
const IMAGE_MIMES = new Set([
  'image/jpeg', 'image/jpg', 'image/png', 'image/webp', 'image/gif',
  'image/heic', 'image/heif',
]);
const DOC_MIMES = new Set([
  'application/pdf',
]);
// "General" uploads (logos, ID docs, bills, watermarks) — image or PDF.
const GENERAL_ALLOWED_MIMES = new Set([...IMAGE_MIMES, ...DOC_MIMES]);

function _makeMimeFilter(allowed: Set<string>) {
  return (_req: Request, file: any, cb: any) => {
    const mime = String(file?.mimetype || '').toLowerCase();
    if (!allowed.has(mime)) {
      // multer treats a thrown error as a rejection; we propagate via
      // cb(null, false) and stash a marker so the error handler returns
      // a proper 415. The route handler can also inspect req.file for null.
      const err: any = new Error(`Unsupported file type: ${mime || 'unknown'}. Allowed: ${[...allowed].join(', ')}`);
      err.code = 'UNSUPPORTED_MIME';
      err.statusCode = 415;
      return cb(err);
    }
    cb(null, true);
  };
}

const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    const uploadDir = path.join(process.cwd(), "public", "uploads");
    if (!fs.existsSync(uploadDir)) {
      fs.mkdirSync(uploadDir, { recursive: true });
    }
    cb(null, uploadDir);
  },
  filename: (req, file, cb) => {
    // T1-S7 — also sanitise the filename. Original code embedded raw
    // user-supplied bytes which is fine for the filesystem but ugly when
    // browsers later download "weird name.exe.jpg" via Content-Disposition.
    const safe = String(file.originalname || 'upload').replace(/[^\w.\-]+/g, '_').slice(0, 120);
    cb(null, `${Date.now()}-${safe}`);
  }
});
const upload = multer({
  storage,
  limits: { fileSize: 10 * 1024 * 1024 },           // 10 MB cap
  fileFilter: _makeMimeFilter(GENERAL_ALLOWED_MIMES),
});

// Menu image uploads use in-memory multer so the buffer can go either to
// Cloudflare R2 (when UPLOAD_BACKEND=r2) or fall back to local disk. The
// other upload endpoints (logos, watermarks, UPI QRs) keep using `upload`
// above — they're low-volume and stay on the VPS filesystem.
const menuImageUpload = multer({
  storage: multer.memoryStorage(),
  limits: { fileSize: 10 * 1024 * 1024 }, // 10 MB cap (modern phone photos often exceed 5 MB)
  // T1-S7 — image-only filter. Menus never need PDF uploads.
  fileFilter: _makeMimeFilter(IMAGE_MIMES),
});

// EARLY-CHECKIN-FIX (regression from S-7): hotel guest ID-proof uploads.
// Same in-memory storage pattern as menuImageUpload (so the handler can
// branch between R2 and local disk by reading req.file.buffer), but with
// the GENERAL_ALLOWED_MIMES whitelist so PDFs (Aadhaar / passport scans)
// are accepted alongside images. Before this fix, the endpoint at
// /hotel/bookings/:bookingId/documents was wired to menuImageUpload —
// which rejected every PDF upload with HTTP 415 and consequently blocked
// check-in for any guest whose only ID doc was a PDF (per Req 1b gate).
const idDocUpload = multer({
  storage: multer.memoryStorage(),
  limits: { fileSize: 10 * 1024 * 1024 },
  fileFilter: _makeMimeFilter(GENERAL_ALLOWED_MIMES),
});

// ── Cloudflare R2 client (lazy-initialised on first use) ─────────────────────
// Keeping this lazy means UPLOAD_BACKEND=disk deployments don't need R2
// credentials configured, and a misconfigured R2 fails loudly at upload time
// rather than blocking server startup.
let _r2Client: S3Client | null = null;
function getR2Client(): S3Client {
  if (_r2Client) return _r2Client;
  const { R2_ACCOUNT_ID, R2_ACCESS_KEY_ID, R2_SECRET_ACCESS_KEY } = process.env;
  if (!R2_ACCOUNT_ID || !R2_ACCESS_KEY_ID || !R2_SECRET_ACCESS_KEY) {
    throw new Error("R2 is enabled but R2_ACCOUNT_ID / R2_ACCESS_KEY_ID / R2_SECRET_ACCESS_KEY are not set");
  }
  _r2Client = new S3Client({
    region: "auto",
    endpoint: `https://${R2_ACCOUNT_ID}.r2.cloudflarestorage.com`,
    credentials: { accessKeyId: R2_ACCESS_KEY_ID, secretAccessKey: R2_SECRET_ACCESS_KEY },
  });
  return _r2Client;
}

const useR2ForMenuImages = () => process.env.UPLOAD_BACKEND === "r2";

/**
 * Persists an uploaded menu image either to Cloudflare R2 or to the local
 * filesystem, depending on UPLOAD_BACKEND. Returns the URL that should be
 * stored in menu.image_url — a full https:// URL when R2 is active, or the
 * legacy "/uploads/<filename>" path otherwise.
 */
async function persistMenuImage(
  restaurantId: string,
  file: Express.Multer.File
): Promise<string> {
  if (useR2ForMenuImages()) {
    const bucket = process.env.R2_BUCKET;
    const baseUrl = process.env.R2_PUBLIC_BASE_URL;
    if (!bucket || !baseUrl) {
      throw new Error("R2 is enabled but R2_BUCKET / R2_PUBLIC_BASE_URL are not set");
    }
    const ext = (file.originalname.match(/\.[a-zA-Z0-9]+$/)?.[0] || ".jpg").toLowerCase();
    const key = `menu/${restaurantId}/${randomUUID()}${ext}`;
    await getR2Client().send(new PutObjectCommand({
      Bucket: bucket,
      Key: key,
      Body: file.buffer,
      ContentType: file.mimetype || "application/octet-stream",
      CacheControl: "public, max-age=31536000, immutable",
    }));
    return `${baseUrl.replace(/\/$/, "")}/${key}`;
  }

  // Disk fallback — mirrors the legacy multer.diskStorage filename scheme so
  // the existing /uploads/:filename handler keeps working unchanged.
  const uploadDir = path.join(process.cwd(), "public", "uploads");
  if (!fs.existsSync(uploadDir)) fs.mkdirSync(uploadDir, { recursive: true });
  const safeName = file.originalname.replace(/[^\w.\-]+/g, "_");
  const filename = `${Date.now()}-${safeName}`;
  fs.writeFileSync(path.join(uploadDir, filename), file.buffer);
  return `/uploads/${filename}`;
}

