  // Admin: Reset Owner Password
  // Updates both legacy users table AND new owner_accounts table
  app.post("/api/admin/reset-owner-password", authenticate, isAdmin, async (req: AuthRequest, res: Response) => {
    const { restaurantId, newPassword } = req.body;
    try {
      const hashedPassword = await bcrypt.hash(newPassword, 12);

      // Legacy path: update users table (older admin-created accounts)
      await centralDb.run(
        "UPDATE users SET password = ? WHERE restaurant_id = ? AND role = 'OWNER'",
        [hashedPassword, restaurantId]
      );

      // New path: update owner_accounts table (self-registered owners).
      // Resolve owner email via owner_restaurants (authoritative FK), with a
      // fallback to restaurants.admin_id for very old rows where admin_id did
      // hold the email directly. Using admin_id alone breaks when it's a user
      // UUID instead of an email (legacy data), which silently leaves the
      // owner_accounts password out of sync with users.password.
      const ownerMap = await centralDb.get(
        "SELECT owner_email FROM owner_restaurants WHERE restaurant_id = ? LIMIT 1",
        [restaurantId]
      );
      let ownerEmail: string | null = ownerMap?.owner_email ?? null;
      if (!ownerEmail) {
        const restaurant = await centralDb.get(
          "SELECT admin_id FROM restaurants WHERE id = ?",
          [restaurantId]
        );
        if (restaurant?.admin_id && String(restaurant.admin_id).includes('@')) {
          ownerEmail = restaurant.admin_id;
        }
      }
      if (ownerEmail) {
        await centralDb.run(
          "UPDATE owner_accounts SET password_hash = ? WHERE LOWER(email) = LOWER(?)",
          [hashedPassword, ownerEmail]
        );
      }

      res.json({ success: true });
    } catch (err) {
      res.status(500).json({ error: "Failed to reset owner password" });
    }
  });

  // Admin: Get Role Permissions for a Restaurant
  app.get("/api/admin/restaurant/:id/role-permissions", authenticate, isAdmin, async (req: AuthRequest, res: Response) => {
    try {
      const rows = await centralDb.query(
        "SELECT role, allowed_tabs FROM restaurant_role_permissions WHERE restaurant_id = ?",
        [req.params.id]
      );
      const result: Record<string, string[]> = {};
      for (const row of rows) {
        try { result[row.role] = JSON.parse(row.allowed_tabs || '[]'); }
        catch { result[row.role] = []; }
      }
      res.json(result);
    } catch (err) {
      res.status(500).json({ error: "Failed to fetch permissions" });
    }
  });

  // Admin: Save Role Permissions for a Restaurant
  app.post("/api/admin/restaurant/:id/role-permissions", authenticate, isAdmin, async (req: AuthRequest, res: Response) => {
    try {
      const permissions: Record<string, string[]> = req.body;
      for (const [role, tabs] of Object.entries(permissions)) {
        await centralDb.run(
          `INSERT INTO restaurant_role_permissions (restaurant_id, role, allowed_tabs, updated_at)
           VALUES (?, ?, ?, CURRENT_TIMESTAMP)
           ON CONFLICT (restaurant_id, role) DO UPDATE SET allowed_tabs = EXCLUDED.allowed_tabs, updated_at = CURRENT_TIMESTAMP`,
          [req.params.id, role, JSON.stringify(tabs)]
        );
      }
      // RBAC-4: invalidate tab cache so the new matrix takes effect
      // on the next mutation request.
      invalidateTabCacheForTenant(req.params.id);
      res.json({ success: true });
    } catch (err) {
      res.status(500).json({ error: "Failed to save permissions" });
    }
  });

  // ─────────────────────────────────────────────────────────────────
  // RBAC-1 — Tenant-scoped role-permissions management
  // ─────────────────────────────────────────────────────────────────
  // Same backing table as the SUPER_ADMIN endpoints above, but
  // accessible to the property OWNER (and SUPER_ADMIN/CTO).
  // Business owners need to configure which staff role sees which
  // tab — front desk gets BOOKINGS but not REPORTS, housekeeping
  // gets only SERVICE_REQUESTS, etc. Without this, owners were
  // blocked from managing their own staff visibility.
  //
  // Guard: caller must be SUPER_ADMIN/CTO OR be the OWNER of this
  // specific tenant. Managers cannot modify permissions — they're
  // the role being managed (least-privilege principle).
  function requireOwnerOrAdmin(req: AuthRequest, res: Response): boolean {
    const role = String(req.user?.role || '').toUpperCase();
    const isPlatformAdmin = role === 'SUPER_ADMIN' || role === 'CTO';
    const isOwnerOfTenant = role === 'OWNER' && req.user?.restaurantId === req.params.id;
    if (!isPlatformAdmin && !isOwnerOfTenant) {
      res.status(403).json({
        error: "Only the property owner (or platform admin) can manage staff access permissions.",
        your_role: role,
      });
      return false;
    }
    return true;
  }

  app.get("/api/restaurant/:id/role-permissions", authenticate, async (req: AuthRequest, res: Response) => {
    if (!requireOwnerOrAdmin(req, res)) return;
    try {
      const rows = await centralDb.query(
        "SELECT role, allowed_tabs, tab_permissions FROM restaurant_role_permissions WHERE restaurant_id = ?",
        [req.params.id]
      );
      // Return new format: Record<role, Record<tabId, level>>
      // Falls back to legacy allowed_tabs (each tab = level 3) when tab_permissions is absent
      const result: Record<string, TabPerms> = {};
      for (const row of rows) {
        if (row.tab_permissions) {
          try {
            const parsed = JSON.parse(row.tab_permissions);
            result[row.role] = (typeof parsed === 'object' && !Array.isArray(parsed)) ? parsed : {};
          } catch { result[row.role] = {}; }
        } else {
          try {
            const arr = JSON.parse(row.allowed_tabs || '[]');
            const obj: TabPerms = {};
            if (Array.isArray(arr)) for (const t of arr) obj[t] = 3;
            result[row.role] = obj;
          } catch { result[row.role] = {}; }
        }
      }
      res.json(result);
    } catch (err) {
      console.error("role-permissions GET error:", err);
      res.status(500).json({ error: "Failed to fetch permissions" });
    }
  });

  app.post("/api/restaurant/:id/role-permissions", authenticate, async (req: AuthRequest, res: Response) => {
    if (!requireOwnerOrAdmin(req, res)) return;
    try {
      // RBAC-6: body is now Record<role, Record<tabId, level (0-3)>>
      const permissions: Record<string, TabPerms> = req.body || {};
      if (typeof permissions !== 'object' || Array.isArray(permissions)) {
        return res.status(400).json({ error: "Body must be an object mapping role → { tabId: level }" });
      }
      // Drop privileged roles — they always have full access
      const sanitized: Record<string, TabPerms> = {};
      for (const [role, perms] of Object.entries(permissions)) {
        const upper = String(role).toUpperCase();
        if (upper === 'OWNER' || upper === 'SUPER_ADMIN' || upper === 'CTO') continue;
        if (typeof perms !== 'object' || Array.isArray(perms)) continue;
        // Clamp levels to 0-3
        const clean: TabPerms = {};
        for (const [tab, lvl] of Object.entries(perms)) {
          const n = Number(lvl);
          clean[tab] = isNaN(n) ? 0 : Math.min(3, Math.max(0, Math.round(n)));
        }
        sanitized[upper] = clean;
      }

      // Pre-load existing rows for audit diffs
      const existing: Record<string, TabPerms> = {};
      const roles = Object.keys(sanitized);
      if (roles.length > 0) {
        const placeholders = roles.map(() => '?').join(',');
        const rows: any[] = await centralDb.query(
          `SELECT role, tab_permissions, allowed_tabs FROM restaurant_role_permissions
            WHERE restaurant_id = ? AND role IN (${placeholders})`,
          [req.params.id, ...roles]
        );
        for (const r of rows) {
          if (r.tab_permissions) {
            try { existing[r.role] = JSON.parse(r.tab_permissions) || {}; } catch { existing[r.role] = {}; }
          } else {
            try {
              const arr = JSON.parse(r.allowed_tabs || '[]');
              const obj: TabPerms = {};
              if (Array.isArray(arr)) for (const t of arr) obj[t] = 3;
              existing[r.role] = obj;
            } catch { existing[r.role] = {}; }
          }
        }
      }

      for (const [role, perms] of Object.entries(sanitized)) {
        const beforeJson = existing[role] !== undefined ? JSON.stringify(existing[role]) : null;
        const afterJson = JSON.stringify(perms);
        if (beforeJson === afterJson) continue;
        await centralDb.run(
          `INSERT INTO restaurant_role_permissions (restaurant_id, role, tab_permissions, updated_at)
           VALUES (?, ?, ?, CURRENT_TIMESTAMP)
           ON CONFLICT (restaurant_id, role) DO UPDATE SET tab_permissions = EXCLUDED.tab_permissions, updated_at = CURRENT_TIMESTAMP`,
          [req.params.id, role, afterJson]
        );
        await centralDb.run(
          `INSERT INTO permission_audit_log
             (restaurant_id, role, allowed_tabs_before, allowed_tabs_after,
              changed_by_id, changed_by_email, changed_by_role)
           VALUES (?, ?, ?, ?, ?, ?, ?)`,
          [req.params.id, role, beforeJson, afterJson,
           req.user?.id || null, req.user?.email || null, req.user?.role || null]
        );
      }
      invalidateTabCacheForTenant(req.params.id);
      res.json({ success: true, saved_roles: Object.keys(sanitized) });
    } catch (err) {
      console.error("role-permissions POST error:", err);
      res.status(500).json({ error: "Failed to save permissions" });
    }
  });

  // RBAC-5a — Read audit log. Last 100 changes, newest first.
  app.get("/api/restaurant/:id/role-permissions/audit", authenticate, async (req: AuthRequest, res: Response) => {
    if (!requireOwnerOrAdmin(req, res)) return;
    try {
      const rows = await centralDb.query(
        `SELECT id, role, allowed_tabs_before, allowed_tabs_after,
                changed_by_id, changed_by_email, changed_by_role, changed_at
           FROM permission_audit_log
          WHERE restaurant_id = ?
          ORDER BY changed_at DESC
          LIMIT 100`,
        [req.params.id]
      );
      // Parse JSON so the client doesn't have to.
      const parsed = rows.map((r: any) => ({
        ...r,
        allowed_tabs_before: r.allowed_tabs_before ? JSON.parse(r.allowed_tabs_before) : null,
        allowed_tabs_after:  r.allowed_tabs_after  ? JSON.parse(r.allowed_tabs_after)  : null,
      }));
      res.json(parsed);
    } catch (err) {
      console.error("role-permissions audit GET error:", err);
      res.status(500).json({ error: "Failed to fetch audit log" });
    }
  });

  // RBAC-5d — List tenants this user can manage permissions on. Used to
  // power the "Copy from another location" dropdown. Returns lightweight
  // metadata (id, name, property_type) for tenants where the caller is
  // OWNER (or for SUPER_ADMIN/CTO — every tenant).
  app.get("/api/restaurant/role-permissions/my-tenants", authenticate, async (req: AuthRequest, res: Response) => {
    try {
      const role = String(req.user?.role || '').toUpperCase();
      const isAdmin = role === 'SUPER_ADMIN' || role === 'CTO';
      const email = req.user?.email;
      const ownerRestaurantId = req.user?.restaurantId;

      let rows: any[] = [];
      if (isAdmin) {
        rows = await centralDb.query(
          `SELECT id, name, property_type FROM restaurants WHERE is_active = 1 ORDER BY name LIMIT 100`
        );
      } else if (email) {
        // Modern email-based owner accounts: lookup restaurants by owner email.
        rows = await centralDb.query(
          `SELECT id, name, property_type FROM restaurants
            WHERE LOWER(admin_id) = LOWER(?) AND is_active = 1
            ORDER BY name`,
          [email]
        );
      } else if (ownerRestaurantId) {
        // Legacy id-based owner: just their own tenant.
        rows = await centralDb.query(
          `SELECT id, name, property_type FROM restaurants WHERE id = ? AND is_active = 1`,
          [ownerRestaurantId]
        );
      }
      res.json(rows);
    } catch (err) {
      console.error("role-permissions my-tenants error:", err);
      res.status(500).json({ error: "Failed to list manageable tenants" });
    }
  });

  // RBAC-5d — Copy permission matrix from source tenant to target tenant.
  // Caller must be OWNER of both (or platform admin). All rows for the
  // source are bulk-upserted onto the target. Audit log captures each
  // resulting change.
  app.post("/api/restaurant/:id/role-permissions/copy-from/:sourceId", authenticate, async (req: AuthRequest, res: Response) => {
    const targetId = req.params.id;
    const sourceId = req.params.sourceId;
    if (targetId === sourceId) {
      return res.status(400).json({ error: "Source and target must be different tenants" });
    }
    const role = String(req.user?.role || '').toUpperCase();
    const isPlatformAdmin = role === 'SUPER_ADMIN' || role === 'CTO';
    try {
      // Authorization: caller must own/admin BOTH tenants. For email-based
      // owners, both must list this email as admin_id.
      if (!isPlatformAdmin) {
        const email = req.user?.email;
        if (!email) return res.status(403).json({ error: "Only the property owner (or platform admin) can copy permissions." });
        const rows = await centralDb.query(
          `SELECT id FROM restaurants WHERE id IN (?, ?) AND LOWER(admin_id) = LOWER(?)`,
          [targetId, sourceId, email]
        );
        if (rows.length !== 2) {
          return res.status(403).json({
            error: "You must own both the source and target properties to copy permissions between them.",
          });
        }
      }

      const sourceRows: any[] = await centralDb.query(
        "SELECT role, allowed_tabs, tab_permissions FROM restaurant_role_permissions WHERE restaurant_id = ?",
        [sourceId]
      );
      if (sourceRows.length === 0) {
        return res.json({ success: true, copied: 0, note: "Source has no configured permissions — nothing to copy." });
      }

      // Pre-load target's existing rows so audit captures real diffs.
      const targetExisting: Record<string, string> = {};
      const targetRows: any[] = await centralDb.query(
        "SELECT role, tab_permissions, allowed_tabs FROM restaurant_role_permissions WHERE restaurant_id = ?",
        [targetId]
      );
      for (const r of targetRows) targetExisting[r.role] = r.tab_permissions || r.allowed_tabs || null;

      let copied = 0;
      for (const r of sourceRows) {
        if (['OWNER', 'SUPER_ADMIN', 'CTO'].includes(r.role)) continue;
        const srcPerms = r.tab_permissions || null;
        const before = targetExisting[r.role] ?? null;
        const after = srcPerms;
        if (!after || before === after) continue;
        await centralDb.run(
          `INSERT INTO restaurant_role_permissions (restaurant_id, role, tab_permissions, updated_at)
           VALUES (?, ?, ?, CURRENT_TIMESTAMP)
           ON CONFLICT (restaurant_id, role) DO UPDATE SET tab_permissions = EXCLUDED.tab_permissions, updated_at = CURRENT_TIMESTAMP`,
          [targetId, r.role, after]
        );
        await centralDb.run(
          `INSERT INTO permission_audit_log
             (restaurant_id, role, allowed_tabs_before, allowed_tabs_after,
              changed_by_id, changed_by_email, changed_by_role)
           VALUES (?, ?, ?, ?, ?, ?, ?)`,
          [targetId, r.role, before, after,
           req.user?.id || null, req.user?.email || null, `${req.user?.role || ''}-copy-from:${sourceId}`]
        );
        copied++;
      }
      invalidateTabCacheForTenant(targetId);
      res.json({ success: true, copied, source: sourceId });
    } catch (err) {
      console.error("role-permissions copy error:", err);
      res.status(500).json({ error: "Failed to copy permissions" });
    }
  });

  // Returns the logged-in user's own tab permissions.
  // Responds with both allowed_tabs (string[] for nav visibility) and
  // tab_permissions (Record<tabId,level> for action-level checks in the UI).
  app.get("/api/restaurant/:id/my-permissions", authenticate, async (req: AuthRequest, res: Response) => {
    try {
      const userRole = req.user?.role;
      const perms = await getTabPermissionsForRole(req.params.id, userRole || '');
      if (perms === null) return res.json({ allowed_tabs: null, tab_permissions: null });
      const allowed_tabs = Object.keys(perms).filter(k => (perms[k] ?? 0) >= 1);
      res.json({
        allowed_tabs: allowed_tabs.length > 0 ? allowed_tabs : null,
        tab_permissions: perms,
      });
    } catch (err) {
      res.status(500).json({ error: "Failed to fetch permissions" });
    }
  });

  // Public: Get Sales Reps
  app.get("/api/public/sales-reps", async (req: Request, res: Response) => {
    try {
      const reps = await centralDb.query("SELECT id, name FROM users WHERE role = 'SALES_REP' AND is_active = 1");
      res.json(reps);
    } catch (err) {
      res.status(500).json({ error: "Failed to fetch sales reps" });
    }
  });

  // Public: Get Restaurants
  app.get("/api/public/restaurants", async (req: Request, res: Response) => {
    try {
      const restaurants = await centralDb.query("SELECT id, name FROM restaurants WHERE is_active = 1");
      res.json(restaurants);
    } catch (err) {
      res.status(500).json({ error: "Failed to fetch public restaurants" });
    }
  });

  // Auth: Get Me
  // For OWNER/SUPER_ADMIN/etc → centralDb.users; for CHEF/WAITER → tenant attendance_staff
  app.get("/api/me", authenticate, async (req: AuthRequest, res: Response) => {
    try {
      // Try centralDb first (OWNER, SUPER_ADMIN, CTO, SALES_REP)
      const centralUser = await centralDb.get(
        "SELECT id, login_id, name, email, phone, role, restaurant_id FROM users WHERE id = ?",
        [req.user?.id]
      );
      if (centralUser) return res.json(centralUser);

      // Fall back to tenant attendance_staff (CHEF, WAITER)
      if (req.user?.restaurantId && req.user.restaurantId !== 'SYSTEM') {
        const tenantDb = await getTenantDb(req.user.restaurantId);
        const staffUser = await tenantDb.get(
          "SELECT id, login_id, name, phone, email, role, default_hours FROM attendance_staff WHERE id = ?",
          [req.user.id]
        );
        if (staffUser) return res.json({ ...staffUser, restaurant_id: req.user.restaurantId });
      }

      return res.status(404).json({ error: "User not found" });
    } catch (err) {
      res.status(500).json({ error: "Failed to fetch user info" });
    }
  });

  // ═════════════════════════════════════════════════════════════════════
  // PHASE B1 — Multi-location / Brand Mode
  // ═════════════════════════════════════════════════════════════════════
  // Resolve every restaurant the *signed-in user* can access. Multi-tenant
  // owners typically register the same email across each location's
  // `users` row, so we look up by email as the canonical identity.
  //   - SUPER_ADMIN / CTO → can see every active restaurant (admin view)
  //   - OWNER / MANAGER   → all restaurants where their email is registered
  //                         as owner / manager
  //   - Staff roles       → only their bound restaurantId from the JWT
  async function _listUserRestaurants(req: AuthRequest): Promise<any[]> {
    const role = String(req.user?.role || '').toUpperCase();
    const email = req.user?.email;
    if (role === 'SUPER_ADMIN' || role === 'CTO') {
      return await centralDb.query(
        `SELECT id, name, brand_id, location_label, city, state, is_active, access_revoked,
                logo_url, property_type
           FROM restaurants
          WHERE id <> 'SYSTEM'
          ORDER BY name ASC`
      ) || [];
    }
    if (email) {
      const rows: any[] = await centralDb.query(
        `SELECT DISTINCT r.id, r.name, r.brand_id, r.location_label, r.city, r.state,
                r.is_active, r.access_revoked, r.logo_url, r.property_type
           FROM users u
           JOIN restaurants r ON r.id = u.restaurant_id
          WHERE u.email = ? AND COALESCE(u.is_active, 1) = 1
            AND r.id <> 'SYSTEM'
          ORDER BY r.name ASC`,
        [email]
      );
      // Always include the JWT's restaurantId even if the user row matching
      // email isn't found (defensive — covers legacy tenants where the
      // owner's email may differ from the users row).
      if (req.user?.restaurantId && !rows.some(r => r.id === req.user!.restaurantId)) {
        const own: any = await centralDb.get(
          "SELECT id, name, brand_id, location_label, city, state, is_active, access_revoked, logo_url, property_type FROM restaurants WHERE id = ?",
          [req.user.restaurantId]
        );
        if (own) rows.unshift(own);
      }
      return rows;
    }
    // Staff fallback — only the bound restaurant
    if (req.user?.restaurantId) {
      const own: any = await centralDb.get(
        "SELECT id, name, brand_id, location_label, city, state, is_active, access_revoked, logo_url, property_type FROM restaurants WHERE id = ?",
        [req.user.restaurantId]
      );
      return own ? [own] : [];
    }
    return [];
  }

  // GET — the user's "switcher" payload: every location + brand grouping
  app.get("/api/brand/my-locations", authenticate, async (req: AuthRequest, res: Response) => {
    try {
      const restaurants = await _listUserRestaurants(req);
      const brandIds = Array.from(new Set(restaurants.map(r => r.brand_id).filter(Boolean)));
      let brands: any[] = [];
      if (brandIds.length > 0) {
        // Per-brand metadata in one query
        const placeholders = brandIds.map(() => '?').join(',');
        brands = await centralDb.query(
          `SELECT id, name, logo_url, description FROM brands WHERE id IN (${placeholders})`,
          brandIds
        ).catch(() => []);
      }
      // Group restaurants under brands; unbranded ones go to a synthetic group
      const groups: any[] = [];
      for (const b of brands) {
        const members = restaurants.filter(r => r.brand_id === b.id);
        if (members.length > 0) groups.push({ ...b, restaurants: members });
      }
      const unbranded = restaurants.filter(r => !r.brand_id);
      if (unbranded.length > 0) {
        groups.push({ id: null, name: 'Unbranded', restaurants: unbranded });
      }
      res.json({
        current_restaurant_id: req.user?.restaurantId || null,
        total_locations: restaurants.length,
        groups,
        all_restaurants: restaurants,
      });
    } catch (err) {
      console.error('my-locations error:', err);
      res.status(500).json({ error: 'Failed to load locations' });
    }
  });

  // POST — silent token refresh. Re-issues a fresh 7-day token with the same
  // claims so an always-open SPA session never silently expires. authenticate()
  // requires the CURRENT token to still be valid; temp/setup tokens (which
  // carry a `purpose` claim) cannot be upgraded to a full session token.
  app.post("/api/auth/refresh", authenticate, async (req: AuthRequest, res: Response) => {
    try {
      const u: any = req.user || {};
      if (u.purpose) return res.status(400).json({ error: 'Temporary tokens cannot be refreshed' });
      const claims: any = {};
      for (const k of ['id', 'restaurantId', 'role', 'email', 'userName', 'phone']) {
        if (u[k] !== undefined && u[k] !== null) claims[k] = u[k];
      }
      const token = jwt.sign(claims, JWT_SECRET, { expiresIn: '7d' });
      try { _setJwtCookie(res, token); } catch {}
      res.json({ token });
    } catch (err: any) {
      res.status(500).json({ error: err?.message || 'Token refresh failed' });
    }
  });

  // POST — switch the JWT to a different restaurant the user can access
  app.post("/api/auth/switch-restaurant", authenticate, async (req: AuthRequest, res: Response) => {
    try {
      const target = String(req.body?.restaurant_id || '').trim();
      if (!target) return res.status(400).json({ error: 'restaurant_id required' });
      const accessible = await _listUserRestaurants(req);
      const match = accessible.find(r => r.id === target);
      if (!match) return res.status(403).json({ error: 'No access to this restaurant' });
      // Re-issue with the new restaurantId, keep everything else identical
      const newToken = jwt.sign(
        {
          id: req.user?.id,
          restaurantId: target,
          role: req.user?.role,
          email: req.user?.email,
          userName: req.user?.userName,
        },
        JWT_SECRET,
        { expiresIn: '7d' }  // 7d session — match cookie maxAge + login paths
      );
      res.json({
        token: newToken,
        restaurantId: target,
        restaurant_name: match.name,
        location_label: match.location_label,
        brand_id: match.brand_id,
      });
    } catch (err) {
      console.error('switch-restaurant error:', err);
      res.status(500).json({ error: 'Switch failed' });
    }
  });

  // GET — aggregate KPIs across every restaurant the user can access.
  //   period = TODAY | YESTERDAY | WTD | MTD | YTD (mirrors A2)
  //   Optional brand_id query param narrows the aggregation.
  app.get("/api/brand/cross-summary", authenticate, async (req: AuthRequest, res: Response) => {
    try {
      const period = String(req.query.period || 'MTD').toUpperCase();
      const brandFilter = req.query.brand_id ? String(req.query.brand_id) : null;
      const accessible = await _listUserRestaurants(req);
      const targets = (brandFilter
        ? accessible.filter(r => r.brand_id === brandFilter)
        : accessible
      ).filter(r => Number(r.is_active || 0) === 1);
      // Date bounds — reuse the same logic A2 already exposes via period-summary.
      // Compute inline to avoid a closure dependency.
      const now = new Date();
      const todayStr = now.toISOString().slice(0, 10);
      let start = todayStr, end = todayStr, label = 'Month to date';
      if (period === 'TODAY') {
        label = 'Today';
      } else if (period === 'YESTERDAY') {
        const y = new Date(now); y.setDate(y.getDate() - 1);
        start = end = y.toISOString().slice(0, 10);
        label = 'Yesterday';
      } else if (period === 'WTD') {
        const dow = now.getDay(); const offset = dow === 0 ? -6 : 1 - dow;
        const mon = new Date(now); mon.setDate(mon.getDate() + offset);
        start = mon.toISOString().slice(0, 10);
        label = 'Week to date';
      } else if (period === 'YTD') {
        start = new Date(now.getFullYear(), 0, 1).toISOString().slice(0, 10);
        label = 'Year to date';
      } else {
        start = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().slice(0, 10);
        label = 'Month to date';
      }
      // Per-restaurant aggregation
      const perRestaurant = [];
      let totalRevenue = 0, totalOrders = 0;
      for (const r of targets) {
        try {
          const db = await getTenantDb(r.id);
          const row: any = await db.get(
            `SELECT COUNT(*) AS orders,
                    COALESCE(SUM(total_amount), 0) AS revenue,
                    COALESCE(AVG(NULLIF(total_amount, 0)), 0) AS aov
               FROM orders
              WHERE created_at >= ? AND created_at < (? :: date + INTERVAL '1 day')
                AND status IN ('CONFIRMED', 'DELIVERED', 'COMPLETED', 'SETTLED', 'PRINTED')`,
            [start, end]
          ).catch(() => ({ orders: 0, revenue: 0, aov: 0 }));
          const rev = Number(row?.revenue || 0);
          const ord = Number(row?.orders || 0);
          perRestaurant.push({
            restaurant_id: r.id,
            restaurant_name: r.name,
            brand_id: r.brand_id,
            location_label: r.location_label,
            city: r.city,
            property_type: r.property_type,
            orders: ord,
            revenue: rev,
            aov: Number(row?.aov || 0),
          });
          totalRevenue += rev;
          totalOrders += ord;
        } catch (err) {
          console.error(`[brand cross-summary] ${r.id} failed:`, err);
          perRestaurant.push({
            restaurant_id: r.id, restaurant_name: r.name,
            brand_id: r.brand_id, location_label: r.location_label,
            city: r.city, property_type: r.property_type,
            orders: 0, revenue: 0, aov: 0, error: 'fetch failed',
          });
        }
      }
      perRestaurant.sort((a, b) => b.revenue - a.revenue);
      res.json({
        period: label, start, end,
        location_count: targets.length,
        totals: {
          revenue: Math.round(totalRevenue * 100) / 100,
          orders: totalOrders,
          aov: totalOrders > 0 ? Math.round((totalRevenue / totalOrders) * 100) / 100 : 0,
        },
        by_restaurant: perRestaurant,
      });
    } catch (err) {
      console.error('cross-summary error:', err);
      res.status(500).json({ error: 'Failed to compute cross-summary' });
    }
  });

