  app.post("/api/admin/data-migration/bookings/import", authenticate, isAdmin, async (req: AuthRequest, res: Response) => {
    try {
      const { tenantId, rows } = req.body as { tenantId: string; rows: any[] };
      if (!tenantId || !Array.isArray(rows) || rows.length === 0) {
        return res.status(400).json({ error: "tenantId and rows[] required" });
      }
      if (rows.length > 2000) return res.status(400).json({ error: "Max 2000 rows per import" });
      const tenantDb = await getTenantDb(tenantId);
      const results: Array<{ index: number; id?: string; error?: string }> = [];
      for (let i = 0; i < rows.length; i++) {
        const r = rows[i];
        if (!r.guest_name || !r.check_in_date || !r.check_out_date) {
          results.push({ index: i, error: "Missing required: guest_name, check_in_date, check_out_date" });
          continue;
        }
        const rnd = Math.random().toString(36).slice(2, 7);
        const id = `BK-MIG-${Date.now()}-${rnd}-${i}`;
        try {
          await tenantDb.run(`
            INSERT INTO room_bookings (
              id, room_id, guest_name, guest_phone, guest_email,
              guest_id_proof, guest_nationality, guest_state,
              num_guests, num_adults,
              check_in_date, check_out_date, status,
              booking_source, room_rate, total_amount,
              special_requests, booking_type,
              payment_status, extra_adults,
              extra_children_with_mattress, extra_children_no_mattress,
              agent_id, commission_pct, commission_amount, net_amount,
              room_locked, created_at
            ) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
          `, [
            id,
            r.room_id || null,
            String(r.guest_name),
            r.guest_phone || null,
            r.guest_email || null,
            r.guest_id_proof || null,
            r.guest_nationality || null,
            r.guest_state || null,
            Number(r.num_guests) || 1,
            r.num_adults ? Number(r.num_adults) : null,
            String(r.check_in_date),
            String(r.check_out_date),
            r.status || 'CHECKED_OUT',
            r.booking_source || 'MIGRATION',
            r.room_rate ? Number(r.room_rate) : 0,
            r.total_amount ? Number(r.total_amount) : 0,
            r.special_requests || null,
            r.booking_type || 'OVERNIGHT',
            r.payment_status || 'UNINVOICED',
            r.extra_adults ? Number(r.extra_adults) : 0,
            r.extra_children_with_mattress ? Number(r.extra_children_with_mattress) : 0,
            r.extra_children_no_mattress ? Number(r.extra_children_no_mattress) : 0,
            r.agent_id || null,
            r.commission_pct ? Number(r.commission_pct) : 0,
            r.commission_amount ? Number(r.commission_amount) : 0,
            r.net_amount ? Number(r.net_amount) : (r.total_amount ? Number(r.total_amount) : 0),
            1,
            r.created_at || new Date().toISOString(),
          ]);
          results.push({ index: i, id });
        } catch (rowErr: any) {
          results.push({ index: i, error: rowErr.message || 'Insert failed' });
        }
      }
      const succeeded = results.filter(r => r.id).length;
      const failed = results.filter(r => r.error).length;
      res.json({ success: true, total: rows.length, succeeded, failed, results });
    } catch (err) {
      console.error("Migration import error:", err);
      res.status(500).json({ error: "Failed to import bookings" });
    }
  });

  // ────────────────────────────────────────────────────────────────────
  // SQL Console — SUPER_ADMIN read-only query interface
  // POST /api/admin/sql-console
  // Body: { tenantId?: string, useCentral?: boolean, sql: string }
  // Only SELECT statements are permitted.
  // ────────────────────────────────────────────────────────────────────
  app.post("/api/admin/sql-console", authenticate, isAdmin, async (req: AuthRequest, res: Response) => {
    try {
      const { tenantId, useCentral, sql: rawSql } = req.body as { tenantId?: string; useCentral?: boolean; sql: string };
      if (!rawSql || typeof rawSql !== 'string') return res.status(400).json({ error: 'sql is required' });

      const trimmed = rawSql.trim();
      const firstWord = trimmed.split(/\s+/)[0].toUpperCase();
      if (!['SELECT', 'EXPLAIN', 'WITH', 'PRAGMA'].includes(firstWord)) {
        return res.status(400).json({ error: 'Only SELECT / WITH / EXPLAIN / PRAGMA statements are allowed in the SQL Console. Use Data Loader for mutations.' });
      }

      let db: DbInterface;
      if (useCentral) {
        db = centralDb;
      } else {
        if (!tenantId) return res.status(400).json({ error: 'tenantId is required when useCentral is false' });
        db = await getTenantDb(String(tenantId));
      }

      const rows = await db.query(trimmed);
      const columns = rows.length > 0 ? Object.keys(rows[0]) : [];
      return res.json({ success: true, columns, rows, rowCount: rows.length });
    } catch (err: any) {
      return res.status(400).json({ error: err.message || 'Query failed' });
    }
  });

  // ────────────────────────────────────────────────────────────────────
  // BCG Demo Tariff Seed (client request 7 Jun 2026)
  // ────────────────────────────────────────────────────────────────────
  // One-click GUI alternative to the qa_seed_viveks_tariff.mts CLI
  // script. SuperAdmin clicks "Seed BCG Demo Tariff" on a restaurant
  // tile → server runs the same idempotent seed (ON CONFLICT DO UPDATE)
  // and returns a JSON summary.
  //
  // Loads the exact pricing matrix from the BCG-onboarding boutique
  // resort spreadsheet: 3 room categories × 2 seasons × 4 meal plans =
  // 24 room tariffs + 24 extra-person charges + 4 season periods + 27
  // sample rooms.
  //
  // Idempotent: re-running refreshes any drifted rates. Wipes +
  // re-inserts season_periods (to avoid duplicate date ranges).
  app.post("/api/admin/tenants/:id/seed-bcg-tariff", authenticate, isAdmin, async (req: AuthRequest, res: Response) => {
    const tenantId = req.params.id;
    try {
      const tenant: any = await centralDb.get(
        "SELECT id, name, property_type FROM restaurants WHERE id = ?",
        [tenantId]
      );
      if (!tenant) return res.status(404).json({ error: `Tenant ${tenantId} not found` });
      if (tenant.property_type !== 'HOTEL' && tenant.property_type !== 'BOTH') {
        return res.status(400).json({
          error: `Tenant property_type is "${tenant.property_type}". Enable the hotel module first (property_type = 'HOTEL' or 'BOTH') so the tariff tables exist on the tenant schema.`,
        });
      }

      // Flip tariff_model so the booking flow uses the matrix path.
      await centralDb.run(
        "UPDATE restaurants SET tariff_model = 'MATRIX' WHERE id = ?",
        [tenantId]
      );

      const db = await getTenantDb(tenantId);

      // 1. Room types (3)
      const ROOM_TYPES = [
        { id: 'SUPERIOR_VIEW', name: 'Superior Room with View',     base: 2000, desc: 'Standard category with city / garden view.',          order: 1 },
        { id: 'PREMIUM_BALC',  name: 'Premium Room with Balcony',   base: 2400, desc: 'Premium category with private balcony.',              order: 2 },
        { id: 'RIVER_VIEW',    name: 'River View with Balcony',     base: 2800, desc: 'Top category — river-facing rooms with private balcony.', order: 3 },
      ];
      for (const rt of ROOM_TYPES) {
        await db.run(
          `INSERT INTO room_types (id, name, description, base_rate, capacity, display_order, is_active)
           VALUES (?, ?, ?, ?, 2, ?, 1)
           ON CONFLICT (id) DO UPDATE SET
             name = EXCLUDED.name, description = EXCLUDED.description,
             base_rate = EXCLUDED.base_rate, display_order = EXCLUDED.display_order`,
          [rt.id, rt.name, rt.desc, rt.base, rt.order]
        );
      }

      // 2. 27 rooms
      const ROOMS_BY_TYPE: Record<string, string[]> = {
        SUPERIOR_VIEW: ['103','203','206','207','209','210','303','306','307','309','310'],
        PREMIUM_BALC:  ['204','205','211','212','304','305','311','312'],
        RIVER_VIEW:    ['101','102','201','202','208','301','302','308'],
      };
      let roomCount = 0;
      for (const [typeId, numbers] of Object.entries(ROOMS_BY_TYPE)) {
        const baseRate = ROOM_TYPES.find(t => t.id === typeId)!.base;
        for (const num of numbers) {
          const id = `ROOM-${num}`;
          const floor = parseInt(num.charAt(0), 10);
          await db.run(
            `INSERT INTO rooms (id, name, room_number, floor, type_id, capacity, base_rate, status, smoking_preference)
             VALUES (?, ?, ?, ?, ?, 2, ?, 'VACANT', 'NON_SMOKING')
             ON CONFLICT (id) DO UPDATE SET
               type_id = EXCLUDED.type_id, base_rate = EXCLUDED.base_rate,
               room_number = EXCLUDED.room_number, floor = EXCLUDED.floor`,
            [id, `Room ${num}`, num, floor, typeId, baseRate]
          );
          roomCount++;
        }
      }

      // 3. Seasons (PEAK + OFF) — auto-seeded by createHotelTables but
      //    defensive upsert in case the tenant pre-dates that change.
      for (const s of [
        { id: 'PEAK', name: 'Peak', desc: 'High-demand months — summer + Christmas / New Year', color: '#c13b3b', order: 1 },
        { id: 'OFF',  name: 'Off',  desc: 'Monsoon + winter shoulder',                          color: '#6b5d52', order: 2 },
      ]) {
        await db.run(
          `INSERT INTO seasons (id, name, description, color, display_order, is_active)
           VALUES (?, ?, ?, ?, ?, 1)
           ON CONFLICT (id) DO UPDATE SET
             name = EXCLUDED.name, description = EXCLUDED.description,
             color = EXCLUDED.color, display_order = EXCLUDED.display_order`,
          [s.id, s.name, s.desc, s.color, s.order]
        );
      }

      // 4. Season periods — wipe + re-insert
      const SEASON_PERIODS = [
        { season_id: 'PEAK', start: '2026-04-15', end: '2026-06-30', label: 'Summer leg (Apr-Jun)' },
        { season_id: 'PEAK', start: '2026-12-20', end: '2027-01-05', label: 'Christmas / New Year leg' },
        { season_id: 'OFF',  start: '2026-07-01', end: '2026-12-19', label: 'Monsoon + post-monsoon' },
        { season_id: 'OFF',  start: '2027-01-06', end: '2027-04-14', label: 'Winter shoulder (Jan-Apr)' },
      ];
      await db.run("DELETE FROM season_periods WHERE season_id IN ('PEAK', 'OFF')");
      for (const p of SEASON_PERIODS) {
        await db.run(
          `INSERT INTO season_periods (id, season_id, start_date, end_date, label)
           VALUES (?, ?, ?, ?, ?)`,
          [`${p.season_id}-${p.start}`, p.season_id, p.start, p.end, p.label]
        );
      }

      // 5. 24 room tariffs
      const TARIFFS: Array<[string, string, string, number]> = [
        ['SUPERIOR_VIEW','PEAK','EP', 3200], ['SUPERIOR_VIEW','PEAK','CP', 3700], ['SUPERIOR_VIEW','PEAK','MAP', 4500], ['SUPERIOR_VIEW','PEAK','API', 5200],
        ['SUPERIOR_VIEW','OFF', 'EP', 2000], ['SUPERIOR_VIEW','OFF', 'CP', 2500], ['SUPERIOR_VIEW','OFF', 'MAP', 3300], ['SUPERIOR_VIEW','OFF', 'API', 4000],
        ['PREMIUM_BALC', 'PEAK','EP', 3700], ['PREMIUM_BALC', 'PEAK','CP', 4200], ['PREMIUM_BALC', 'PEAK','MAP', 5000], ['PREMIUM_BALC', 'PEAK','API', 5700],
        ['PREMIUM_BALC', 'OFF', 'EP', 2400], ['PREMIUM_BALC', 'OFF', 'CP', 2900], ['PREMIUM_BALC', 'OFF', 'MAP', 3700], ['PREMIUM_BALC', 'OFF', 'API', 4400],
        ['RIVER_VIEW',   'PEAK','EP', 4200], ['RIVER_VIEW',   'PEAK','CP', 4700], ['RIVER_VIEW',   'PEAK','MAP', 5500], ['RIVER_VIEW',   'PEAK','API', 6200],
        ['RIVER_VIEW',   'OFF', 'EP', 2800], ['RIVER_VIEW',   'OFF', 'CP', 3300], ['RIVER_VIEW',   'OFF', 'MAP', 4100], ['RIVER_VIEW',   'OFF', 'API', 4800],
      ];
      for (const [typeId, seasonId, mealId, rate] of TARIFFS) {
        await db.run(
          `INSERT INTO room_tariffs (id, room_type_id, season_id, meal_plan_id, rate, room_id_override)
           VALUES (?, ?, ?, ?, ?, NULL)
           ON CONFLICT (room_type_id, season_id, meal_plan_id, COALESCE(room_id_override, ''))
           DO UPDATE SET rate = EXCLUDED.rate, updated_at = CURRENT_TIMESTAMP`,
          [`TARIFF-${typeId}-${seasonId}-${mealId}`, typeId, seasonId, mealId, rate]
        );
      }

      // 6. 24 extra-person charges
      const EXTRAS: Array<[string, string, string, number]> = [
        ['ADULT',              'PEAK','EP',1000], ['ADULT',              'PEAK','CP',1300], ['ADULT',              'PEAK','MAP',1800], ['ADULT',              'PEAK','API',2200],
        ['ADULT',              'OFF', 'EP', 800], ['ADULT',              'OFF', 'CP',1100], ['ADULT',              'OFF', 'MAP',1600], ['ADULT',              'OFF', 'API',2000],
        ['CHILD_WITH_MATTRESS','PEAK','EP', 700], ['CHILD_WITH_MATTRESS','PEAK','CP',1000], ['CHILD_WITH_MATTRESS','PEAK','MAP',1400], ['CHILD_WITH_MATTRESS','PEAK','API',1700],
        ['CHILD_WITH_MATTRESS','OFF', 'EP', 500], ['CHILD_WITH_MATTRESS','OFF', 'CP', 800], ['CHILD_WITH_MATTRESS','OFF', 'MAP',1200], ['CHILD_WITH_MATTRESS','OFF', 'API',1500],
        ['CHILD_NO_MATTRESS', 'PEAK','EP', 500], ['CHILD_NO_MATTRESS', 'PEAK','CP', 700], ['CHILD_NO_MATTRESS', 'PEAK','MAP',1000], ['CHILD_NO_MATTRESS', 'PEAK','API',1200],
        ['CHILD_NO_MATTRESS', 'OFF', 'EP', 400], ['CHILD_NO_MATTRESS', 'OFF', 'CP', 600], ['CHILD_NO_MATTRESS', 'OFF', 'MAP', 900], ['CHILD_NO_MATTRESS', 'OFF', 'API',1100],
      ];
      for (const [personType, seasonId, mealId, charge] of EXTRAS) {
        const isChild = personType.startsWith('CHILD');
        await db.run(
          `INSERT INTO extra_person_charges (id, person_type, season_id, meal_plan_id, age_min, age_max, charge)
           VALUES (?, ?, ?, ?, ?, ?, ?)
           ON CONFLICT (person_type, season_id, meal_plan_id)
           DO UPDATE SET charge = EXCLUDED.charge,
                         age_min = EXCLUDED.age_min, age_max = EXCLUDED.age_max`,
          [`XP-${personType}-${seasonId}-${mealId}`, personType, seasonId, mealId,
           isChild ? 5 : null, isChild ? 12 : null, charge]
        );
      }

      res.json({
        ok: true,
        tenant: { id: tenant.id, name: tenant.name },
        seeded: {
          room_types: ROOM_TYPES.length,
          rooms: roomCount,
          season_periods: SEASON_PERIODS.length,
          room_tariffs: TARIFFS.length,
          extra_person_charges: EXTRAS.length,
        },
        tariff_model: 'MATRIX',
        message: `BCG demo tariff loaded for ${tenant.name}. Visit Settings → Tariff Configuration to verify the matrix; create a test booking to confirm the rate resolver picks up the new rates.`,
      });
    } catch (err: any) {
      console.error('[admin] seed-bcg-tariff failed:', err);
      res.status(500).json({ error: err?.message || 'Seed failed' });
    }
  });

  // ────────────────────────────────────────────────────────────────────
  // OTA Demo Data Seed (client request 9 Jun 2026)
  // ────────────────────────────────────────────────────────────────────
  // Companion to seed-bcg-tariff. Once the tariff matrix + rooms are in
  // place, this populates OTA-side data so the new Channel Manager
  // dashboards (360°, Live Rate Card, Commission Summary, Queue,
  // Reconciliation) light up immediately.
  //
  // User explicitly authorized seeding fabricated bookings into the
  // viveks-cafe live tenant ("Proceed on viveks-cafe as-is" — 9 Jun
  // 2026). Every seeded row carries an "OTA-SEED-" id prefix so it is
  // unambiguously identifiable and removable later; every guest_name
  // ends with "(demo)" so it is visible in any guest-facing list.
  //
  // What gets seeded:
  //   • 6 channel_credentials with realistic commission % (BDC 15, MMT
  //     20, GIB 18, AGO 17, EXP 16, ABB 14)
  //   • ~250 room_bookings across last 90 days + next 30 days with
  //     realistic channel-mix shares, lead times, ALOS, cancel rate
  //   • commission_pct / commission_amount / net_amount snapshotted per
  //     booking
  //   • channel_sync_log rows (success + failed + perm-failed)
  //   • reconciliation reports (ok + mismatch + stub)
  //   • webhook log entries (verified)
  //
  // Channel mix (BCG-realistic for a boutique Indian property):
  //   BOOKING 30 / MMT 22 / GOIBIBO 15 / DIRECT 12 / AGODA 8 /
  //   EXPEDIA 5 / AIRBNB 4 / WALK_IN 4
  //
  // Idempotent: re-running uses ON CONFLICT DO NOTHING on every INSERT.
  app.post("/api/admin/tenants/:id/seed-ota-demo", authenticate, isAdmin, async (req: AuthRequest, res: Response) => {
    const tenantId = req.params.id;
    try {
      const tenant: any = await centralDb.get(
        "SELECT id, name, property_type FROM restaurants WHERE id = ?",
        [tenantId]
      );
      if (!tenant) return res.status(404).json({ error: `Tenant ${tenantId} not found` });
      if (tenant.property_type !== 'HOTEL' && tenant.property_type !== 'BOTH') {
        return res.status(400).json({
          error: `Tenant property_type is "${tenant.property_type}". This seed only works for HOTEL or BOTH.`,
        });
      }

      const db = await getTenantDb(tenantId);

      const rooms: any[] = await db.query("SELECT id, base_rate FROM rooms WHERE COALESCE(status,'VACANT') != 'INACTIVE' LIMIT 50").catch(() => []);
      if (rooms.length === 0) {
        return res.status(400).json({ error: 'No rooms found for this tenant. Run "Seed BCG Tariff" first to create rooms.' });
      }

      // ── 1. Channel credentials with realistic commission % ──────────
      const CHANNELS = [
        { code: 'BOOKING', commission: 15, property: 'BDC-12345678' },
        { code: 'MMT',     commission: 20, property: 'MMT-87654321' },
        { code: 'GOIBIBO', commission: 18, property: 'GIB-11223344' },
        { code: 'AGODA',   commission: 17, property: 'AGO-99887766' },
        { code: 'EXPEDIA', commission: 16, property: 'EXP-55443322' },
        { code: 'AIRBNB',  commission: 14, property: 'ABB-77665544' },
      ];
      for (const c of CHANNELS) {
        await db.run(
          `INSERT INTO channel_credentials (id, channel, api_key, api_secret, property_id, is_enabled, commission_pct, webhook_signing_secret)
           VALUES (?, ?, ?, ?, ?, 1, ?, ?)
           ON CONFLICT (channel) DO UPDATE SET
             commission_pct = EXCLUDED.commission_pct,
             property_id    = COALESCE(channel_credentials.property_id, EXCLUDED.property_id),
             is_enabled     = 1`,
          [`CRED-${c.code}`, c.code, encryptSecret('demo-key-' + c.code), encryptSecret('demo-secret-' + c.code),
           c.property, c.commission, encryptSecret('demo-webhook-' + c.code)]
        ).catch((e: any) => console.error(`[seed-ota] credential ${c.code}:`, e?.message));
      }

      // ── 2. Booking generator ────────────────────────────────────────
      const CHANNEL_MIX = [
        { code: 'BOOKING', share: 30, commission: 15 },
        { code: 'MMT',     share: 22, commission: 20 },
        { code: 'GOIBIBO', share: 15, commission: 18 },
        { code: 'DIRECT',  share: 12, commission: 0 },
        { code: 'AGODA',   share:  8, commission: 17 },
        { code: 'EXPEDIA', share:  5, commission: 16 },
        { code: 'AIRBNB',  share:  4, commission: 14 },
        { code: 'WALK_IN', share:  4, commission: 0 },
      ];
      const pickChannel = () => {
        const r = Math.random() * 100;
        let acc = 0;
        for (const c of CHANNEL_MIX) { acc += c.share; if (r <= acc) return c; }
        return CHANNEL_MIX[0];
      };

      const FIRST_NAMES = ['Aarav','Vivaan','Aditya','Vihaan','Arjun','Reyansh','Krishna','Ishaan','Shaurya','Atharv',
                            'Priya','Ananya','Sara','Aanya','Ishita','Saanvi','Kavya','Pari','Riya','Aadhya',
                            'Rajesh','Amit','Suresh','Vikram','Ravi','Anjali','Pooja','Neha','Sunita','Meera',
                            'John','Emma','Michael','Olivia','David','Sophie','James','Maya','Daniel','Aisha'];
      const LAST_NAMES  = ['Sharma','Patel','Kumar','Singh','Gupta','Reddy','Nair','Iyer','Rao','Joshi',
                            'Verma','Mehta','Shah','Agarwal','Bhat','Smith','Johnson','Brown','Wilson','Davis'];
      const pickName  = () => `${FIRST_NAMES[Math.floor(Math.random() * FIRST_NAMES.length)]} ${LAST_NAMES[Math.floor(Math.random() * LAST_NAMES.length)]} (demo)`;
      const pickPhone = () => `+91-90000${String(Math.floor(Math.random() * 99999)).padStart(5, '0')}`;
      const nightWeights = [1, 1, 2, 3, 3, 3, 2, 1, 1, 1];
      const pickNights = () => nightWeights[Math.floor(Math.random() * nightWeights.length)];

      const today = new Date();
      const toIso = (d: Date) => d.toISOString().slice(0, 10);
      const addDays = (d: Date, n: number) => { const c = new Date(d); c.setDate(c.getDate() + n); return c; };

      const TARGET = 250;
      let inserted = 0, cancelled = 0, checkedOut = 0, checkedIn = 0, booked = 0;
      const channelCounts: Record<string, number> = {};
      for (let i = 0; i < TARGET; i++) {
        const futurePick = Math.random() < 0.15;
        const offsetDays = futurePick
          ? Math.floor(Math.random() * 30) + 1
          : -Math.floor(Math.random() * 90);
        const checkIn = addDays(today, offsetDays);
        const nights  = pickNights();
        const checkOut = addDays(checkIn, nights);
        const ch = pickChannel();
        const room = rooms[Math.floor(Math.random() * rooms.length)];
        const baseRate = Number(room.base_rate || 2500);
        const rateMult = 0.85 + Math.random() * 0.30;
        const roomRate = Math.round(baseRate * rateMult);
        const total    = roomRate * nights;
        const commPct  = ch.commission;
        const commAmt  = Math.round(total * commPct) / 100;
        const netAmt   = Math.round((total - commAmt) * 100) / 100;

        let status: string;
        let actualCheckIn: string | null = null;
        let actualCheckOut: string | null = null;
        const isPast    = checkOut < today;
        const isOngoing = checkIn <= today && checkOut > today;
        const cancelRoll = Math.random();
        if (cancelRoll < 0.10) {
          status = 'CANCELLED'; cancelled++;
        } else if (isPast) {
          status = 'CHECKED_OUT';
          actualCheckIn  = `${toIso(checkIn)} 14:30:00`;
          actualCheckOut = `${toIso(checkOut)} 11:00:00`;
          checkedOut++;
        } else if (isOngoing) {
          if (Math.random() < 0.7) { status = 'CHECKED_IN'; actualCheckIn = `${toIso(checkIn)} 14:30:00`; checkedIn++; }
          else { status = 'BOOKED'; booked++; }
        } else {
          status = 'BOOKED'; booked++;
        }

        const leadDays = ch.code === 'WALK_IN' ? 0
                       : ch.code === 'AIRBNB' || ch.code === 'EXPEDIA' ? Math.floor(Math.random() * 60) + 5
                       : Math.floor(Math.random() * 30) + 1;
        const createdAt = toIso(addDays(checkIn, -leadDays));

        // Cancellation attribution for seeded data so the Cancelled
        // Reservations report shows varied "Cancelled by" sources: an OTA
        // channel cancels OTA bookings; direct bookings split between the
        // guest (online) and the front desk.
        let cancelledAt: string | null = null;
        let cancelledSource: string | null = null;
        let cancelledBy: string | null = null;
        let cancelReason: string | null = null;
        if (status === 'CANCELLED') {
          cancelledAt = `${toIso(addDays(checkIn, -Math.max(1, Math.floor(leadDays / 2))))} 10:30:00`;
          const codeU = String(ch.code).toUpperCase();
          if (!['DIRECT', 'DIRECT_WEB', 'WALK_IN'].includes(codeU)) {
            cancelledSource = 'OTA'; cancelledBy = ch.code; cancelReason = `Cancelled via ${ch.code}`;
          } else if (codeU === 'WALK_IN') {
            cancelledSource = 'STAFF'; cancelReason = 'Front desk cancellation';
          } else if (Math.random() < 0.5) {
            cancelledSource = 'GUEST_ONLINE'; cancelReason = 'Guest self-cancelled online';
          } else {
            cancelledSource = 'STAFF'; cancelReason = 'Front desk cancellation';
          }
        }

        const id = `OTA-SEED-${tenantId.replace(/-/g, '').slice(0, 6)}-${String(i).padStart(4, '0')}`;
        const guestName = pickName();
        const numGuests = Math.random() < 0.6 ? 2 : Math.random() < 0.85 ? 1 : 3;

        try {
          await db.run(
            `INSERT INTO room_bookings (
                id, room_id, guest_name, guest_phone, num_guests,
                check_in_date, check_out_date, actual_checkin_at, actual_checkout_at,
                status, booking_source, room_rate, total_amount,
                commission_pct, commission_amount, net_amount,
                booking_type, created_at,
                cancelled_at, cancelled_source, cancelled_by, cancellation_reason
              ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'OVERNIGHT', ?, ?, ?, ?, ?)
              ON CONFLICT (id) DO NOTHING`,
            [id, room.id, guestName, pickPhone(), numGuests,
             toIso(checkIn), toIso(checkOut), actualCheckIn, actualCheckOut,
             status, ch.code, roomRate, total,
             commPct, commAmt, netAmt, createdAt,
             cancelledAt, cancelledSource, cancelledBy, cancelReason]
          );
          inserted++;
          channelCounts[ch.code] = (channelCounts[ch.code] || 0) + 1;
        } catch (e: any) { /* room-overlap conflict — skip silently */ }
      }

      // ── 3. Channel sync queue ───────────────────────────────────────
      const SYNC_ROWS = [
        { ch: 'BOOKING', op: 'rate_update',    status: 'success', err: null, retries: 0 },
        { ch: 'MMT',     op: 'inventory_push', status: 'success', err: null, retries: 0 },
        { ch: 'GOIBIBO', op: 'rate_update',    status: 'queued',  err: null, retries: 0 },
        { ch: 'AGODA',   op: 'rate_update',    status: 'failed',  err: 'HTTP 503 - service unavailable', retries: 2 },
        { ch: 'EXPEDIA', op: 'inventory_push', status: 'permanently_failed', err: 'HTTP 401 - signature mismatch (rotated key?)', retries: 5 },
      ];
      for (let i = 0; i < SYNC_ROWS.length; i++) {
        const r = SYNC_ROWS[i];
        const nextRetry = r.status === 'failed' ? today.toISOString() : null;
        await db.run(
          `INSERT INTO channel_sync_log (id, channel, operation, status, payload, response, error, retry_count, next_retry_at, created_at)
           VALUES (?, ?, ?, ?, '{}', NULL, ?, ?, ?, ?)
           ON CONFLICT (id) DO NOTHING`,
          [`OTA-SEED-SYNC-${i}`, r.ch, r.op, r.status, r.err, r.retries, nextRetry, addDays(today, -1).toISOString()]
        ).catch(() => {});
      }

      // ── 4. Reconciliation reports ───────────────────────────────────
      const RECON_ROWS = [
        { ch: 'BOOKING', local: 18, remote: 18, missingL: 0, missingR: 0, status: 'ok' },
        { ch: 'MMT',     local: 12, remote: 13, missingL: 1, missingR: 0, status: 'mismatch' },
        { ch: 'GOIBIBO', local: 8,  remote: 0,  missingL: 0, missingR: 0, status: 'stub' },
      ];
      for (let i = 0; i < RECON_ROWS.length; i++) {
        const r = RECON_ROWS[i];
        await db.run(
          `INSERT INTO channel_reconciliation_reports
              (id, channel, ran_at, period_start, period_end, local_count, remote_count, missing_in_local, missing_in_remote, status, summary_json)
           VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, '{}')
           ON CONFLICT (id) DO NOTHING`,
          [`OTA-SEED-RECON-${i}`, r.ch, addDays(today, -1).toISOString(), toIso(addDays(today, -1)), toIso(today),
           r.local, r.remote, r.missingL, r.missingR, r.status]
        ).catch(() => {});
      }

      // ── 5. Webhook log entries ──────────────────────────────────────
      for (let i = 0; i < 8; i++) {
        const ch = CHANNEL_MIX[i % 6];
        await db.run(
          `INSERT INTO channel_webhook_log (id, channel, event_type, signature_valid, body, received_at)
           VALUES (?, ?, ?, 1, '{}', ?)
           ON CONFLICT (id) DO NOTHING`,
          [`OTA-SEED-HOOK-${i}`, ch.code, i % 3 === 0 ? 'reservation_cancelled' : 'reservation_created',
           addDays(today, -Math.floor(Math.random() * 7)).toISOString()]
        ).catch(() => {});
      }

      res.json({
        ok: true,
        tenant: { id: tenant.id, name: tenant.name },
        seeded: {
          channels: CHANNELS.length,
          bookings_attempted: TARGET,
          bookings_inserted: inserted,
          breakdown: { booked, checked_in: checkedIn, checked_out: checkedOut, cancelled },
          per_channel: channelCounts,
          sync_queue_rows: SYNC_ROWS.length,
          reconciliation_reports: RECON_ROWS.length,
          webhook_log_entries: 8,
        },
        message: `OTA demo data seeded for ${tenant.name}. Visit Channel Manager to see the 360° dashboard light up. Every seeded row carries an "OTA-SEED-" id prefix so they can be identified and removed later if needed.`,
      });
    } catch (err: any) {
      console.error('[admin] seed-ota-demo failed:', err);
      res.status(500).json({ error: err?.message || 'Seed failed' });
    }
  });

  // Tenant-facing: fetch own billing status (called hourly by the banner).
  // Returns minimal info — no admin-only fields like revoked_by.
  app.get("/api/restaurant/:id/billing-status", authenticate, async (req: AuthRequest, res: Response) => {
    try {
      const tenantId = req.params.id;
      // Authorisation — anyone authenticated for this tenant or an admin can read.
      const role = req.user?.role;
      const ownTenant = req.user?.restaurantId;
      const isAdminRole = role === 'SUPER_ADMIN' || role === 'CTO';
      if (!isAdminRole && ownTenant !== tenantId) {
        return res.status(403).json({ error: "Forbidden" });
      }
      const row: any = await centralDb.get(
        `SELECT id, name, is_active, subscription_plan, subscription_due_date, grace_period_days,
                access_revoked, access_revoked_at, access_revoked_reason,
                last_payment_date
           FROM restaurants WHERE id = ?`,
        [tenantId]
      );
      if (!row) return res.status(404).json({ error: "Tenant not found" });
      const days = _daysUntilDue(row.subscription_due_date);
      const status = _billingStatusOf(row);
      // tenant_inactive trumps everything else for the frontend lock screen.
      // is_active values: 0=pending, 1=active, 2=admin-suspended. Anything
      // other than 1 = inactive from the user's perspective.
      const tenantInactive = Number(row.is_active) !== 1;
      // read-only mode has TWO triggers — keep the frontend in sync with the
      // server-side middleware so the banner + fetch-interceptor match what
      // the API actually enforces:
      //   (a) access_revoked = 1            → admin manually revoked
      //   (b) past due date + grace period  → automatic
      const pastGrace = isTenantPastGrace(row);
      const accessRevoked = Number(row.access_revoked) === 1;
      const readOnly = accessRevoked || pastGrace;
      const dpd = daysPastDue(row);
      res.json({
        tenant_id: row.id,
        tenant_name: row.name,
        is_active: !tenantInactive,
        tenant_inactive: tenantInactive,
        subscription_plan: row.subscription_plan,
        subscription_due_date: row.subscription_due_date,
        grace_period_days: row.grace_period_days ?? 7,
        days_until_due: days,
        days_past_due: dpd,
        last_payment_date: row.last_payment_date,
        access_revoked: accessRevoked,
        access_revoked_at: row.access_revoked_at,
        access_revoked_reason: row.access_revoked_reason,
        past_grace: pastGrace,
        read_only: readOnly,
        read_only_reason: accessRevoked
          ? (row.access_revoked_reason || 'Subscription payment overdue')
          : (pastGrace ? `Subscription payment is ${dpd} day${dpd === 1 ? '' : 's'} overdue (past grace period)` : null),
        billing_status: tenantInactive ? 'INACTIVE' : status,
        billing_contact: {
          email: 'billing@atithi-setu.com',
          whatsapp: '+91 70111 89371',
        },
      });
    } catch (err) {
      console.error("Get billing status error:", err);
      res.status(500).json({ error: "Failed to get billing status" });
    }
  });

